export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveKeys = new Set(liveCells.map(([x, y]) => `${x},${y}`));

  const survivors = liveCells.filter((cell) => {
    const neighborCount = liveCells.filter((n) => isNeighbor(cell, n)).length;
    return neighborCount >= 2 && neighborCount <= 3;
  });

  const deadCandidateKeys = new Set<string>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        if (!liveKeys.has(key)) deadCandidateKeys.add(key);
      }
    }
  }

  const born = [...deadCandidateKeys]
    .map((key) => key.split(",").map(Number) as Cell)
    .filter((candidate) => liveCells.filter((n) => isNeighbor(candidate, n)).length === 3);

  return [...survivors, ...born];
};

